## Platform-Level Issues Investigation

### 3. WhatsApp Business API Platform Health
```javascript
// Check platform status and limits
async function checkPlatformHealth() {
    try {
        // Verify API connectivity
        const response = await fetch(`https://graph.facebook.com/v18.0/${PHONE_NUMBER_ID}`, {
            headers: { 'Authorization': `Bearer ${ACCESS_TOKEN}` }
        });

        if (!response.ok) {
            console.error('Platform connectivity issue:', response.status);
            return false;
        }

        // Check rate limits
        const rateLimitRemaining = response.headers.get('x-app-usage');
        const businessUsage = response.headers.get('x-business-use-case-usage');

        console.log('Rate limit status:', { rateLimitRemaining, businessUsage });

        return true;
    } catch (error) {
        console.error('Platform health check failed:', error);
        return false;
    }
}
```

### 4. Message Quality Rating Analysis
```javascript
// Check if account has been flagged for spam
async function checkQualityRating() {
    const response = await fetch(
        `https://graph.facebook.com/v18.0/${PHONE_NUMBER_ID}?fields=quality_rating,status`, {
        headers: { 'Authorization': `Bearer ${ACCESS_TOKEN}` }
    });

    const data = await response.json();

    if (data.quality_rating === 'RED' || data.quality_rating === 'YELLOW') {
        console.error('Quality rating issue detected:', data.quality_rating);
        return {
            issue: 'QUALITY_RATING',
            rating: data.quality_rating,
            status: data.status
        };
    }

    return { status: 'healthy', rating: data.quality_rating };
}
```

## Application-Level Debugging

### 5. Message Flow Analysis
```javascript
// Audit message sending logic
class MessageAuditor {
    async auditOutboundMessages(timeRange = '24h') {
        const messages = await this.getMessageLogs(timeRange);

        const analysis = {
            totalSent: messages.length,
            delivered: messages.filter(m => m.status === 'delivered').length,
            failed: messages.filter(m => m.status === 'failed').length,
            pending: messages.filter(m => m.status === 'pending').length,
            duplicates: this.findDuplicates(messages),
            rateLimitHits: messages.filter(m => m.error_code === 131048).length
        };

        // Check for spam patterns
        const spamIndicators = this.detectSpamPatterns(messages);

        return { ...analysis, spamIndicators };
    }

    detectSpamPatterns(messages) {
        const patterns = {
            highFrequency: this.checkHighFrequencyUsers(messages),
            duplicateContent: this.checkDuplicateContent(messages),
            suspiciousTemplates: this.checkTemplateUsage(messages),
            broadcastSpam: this.checkBroadcastPatterns(messages)
        };

        return patterns;
    }

    checkHighFrequencyUsers(messages) {
        const userMessageCount = {};
        messages.forEach(msg => {
            userMessageCount[msg.to] = (userMessageCount[msg.to] || 0) + 1;
        });

        // Flag users receiving >10 messages in 24h
        return Object.entries(userMessageCount)
            .filter(([user, count]) => count > 10)
            .map(([user, count]) => ({ user, count }));
    }
}
```

### 6. Message Template and Content Validation
```javascript
// Validate message templates and content
class ContentValidator {
    validateMessageContent(message) {
        const issues = [];

        // Check for spam keywords
        const spamKeywords = ['urgent', 'limited time', 'act now', 'free money'];
        const hasSpamKeywords = spamKeywords.some(keyword => 
            message.text?.toLowerCase().includes(keyword.toLowerCase())
        );

        if (hasSpamKeywords) {
            issues.push('SPAM_KEYWORDS_DETECTED');
        }

        // Check message length
        if (message.text && message.text.length > 4096) {
            issues.push('MESSAGE_TOO_LONG');
        }

        // Validate template parameters
        if (message.template) {
            const templateIssues = this.validateTemplate(message.template);
            issues.push(...templateIssues);
        }

        return issues;
    }

    validateTemplate(template) {
        const issues = [];

        // Check if template is approved
        if (!template.approved) {
            issues.push('TEMPLATE_NOT_APPROVED');
        }

        // Validate parameter count
        const expectedParams = template.components
            ?.reduce((count, comp) => count + (comp.parameters?.length || 0), 0);

        if (template.parameters?.length !== expectedParams) {
            issues.push('TEMPLATE_PARAMETER_MISMATCH');
        }

        return issues;
    }
}
```

